/* =============================================================================
   SEAL — Seed data (V2)  |  Microsoft SQL Server (T-SQL)
   Run AFTER V1__init_schema.sql. Context: FPT University students.

   PASSWORD NOTE (read this!):
     Every demo account uses the plaintext password:  demo1234
     The column users.password_hash needs a BCrypt hash. SQL cannot compute
     BCrypt, so the @pwd value below is a VALID-FORMAT PLACEHOLDER only.
     Before login will work, replace @pwd with a real hash generated by the
     SAME encoder your Spring app uses, e.g. in a throwaway test:
         new BCryptPasswordEncoder().encode("demo1234")
     then paste the result (starts with $2a$10$...) into @pwd.

   IDs: this script uses SET IDENTITY_INSERT so foreign keys reference
     deterministic ids (users 1..15, season 1, competition 1, rounds 1..3,
     criteria 1..15, teams 1..3, judges 1..3). Leaf tables auto-generate ids.

   Idempotency: this seed assumes empty tables (fresh DB / Flyway V2).
============================================================================= */

SET NOCOUNT ON;

DECLARE @pwd NVARCHAR(255) = N'$2a$10$N9qo8uLOickgx2ZMRZoMyeIjZAgcfl7p92ldGxad68LJZdL17lhWy';
-- ^ REPLACE with BCrypt hash of "demo1234" (see PASSWORD NOTE above).

